indexTs:
import { SCENARIO_EVENTS } from "./events";
import { getRules } from "./rules";
import { SCENARIO_RULE_SHEETS } from "./ruleSheets";
import { checkScenarioEnding } from "./endings";
import { SCENARIO_DIALOGUES } from "./dialogues";
import { SCENARIO_LOCATIONS } from "./locationActions";

export type PlayerState = {
  currentLocation: string;
  timeMinutes: number;
  sanity: number;
  suspicion: number;
  foundSheets: string[];
  discoveredClues: string[];
  logs: { time: string; text: string }[];
  [key: string]: unknown;
};

export type WorldState = {
  hotelRealityStability: number;
  anomalyAttention: number;
  ruleNoticeVersion: number;
  staffMode: "normal" | "watching" | "hostile" | "false_helpful";
  [key: string]: unknown;
};

export type Effect = {
  type:
    | "sanity"
    | "suspicion"
    | "time"
    | "location"
    | "flag"
    | "clue"
    | "world"
    | "ending"
    | "anomaly"
    | "sheet";
  key?: string;
  value?: number | boolean | string;
};

export type Choice = {
  id: string;
  label: string;
  resultText: string;
  effects: Effect[];
  nextLocation?: string;
  condition?: (player: PlayerState, world: WorldState) => boolean;
};

export type GameEvent = {
  id: string;
  title: string;
  trigger: (player: PlayerState, world: WorldState) => boolean;
  description: string;
  choices: Choice[];
  once?: boolean;
};

export type LocationAction = {
  id: string;
  label: string;
  condition?: (player: PlayerState, world: WorldState) => boolean;
  resultText: string | ((player: PlayerState, world: WorldState) => string);
  effects: Effect[];
};

export type LocationData = {
  id: string;
  name: string;
  mutatedName?: string;
  description: string | "dynamic";
  adjacentLocations: string[];
  actions: LocationAction[];
};

export type Dialogue = {
  id: string;
  npcName: string;
  startScene: string;
  scenes: Record<
    string,
    {
      npcText: string | "dynamic";
      choices: {
        id: string;
        label: string;
        condition?: (player: PlayerState, world: WorldState) => boolean;
        effects?: Effect[];
        setMemory?: Record<string, boolean | string>;
        next: string | null;
      }[];
    }
  >;
};

export type RuleSheet = {
  id: string;
  title: string;
  source: "official" | "previous_occupant" | "staff" | "unknown";
  lines: string[];
};

export type GameEnding = {
  id: string;
  title: string;
  text: string;
  condition: (player: PlayerState, world: WorldState) => boolean;
};

export type ScenarioPack = {
  id: string;
  name: string;
  nameEn: string;
  tagline: string;
  description: string;
  initialPlayer: PlayerState;
  initialWorld: WorldState;
  locations: LocationData[];
  events: GameEvent[];
  dialogues: Dialogue[];
  ruleSheets: RuleSheet[];
  getRules: (player: PlayerState, world: WorldState) => string[];
  checkEnding: (player: PlayerState, world: WorldState) => GameEnding | null;
};

const START_MINUTES = 1303;

const initialPlayer: PlayerState = {
  currentLocation: "dorm_room",
  timeMinutes: START_MINUTES,
  sanity: 100,
  suspicion: 0,
  foundSheets: [],
  discoveredClues: [],
  logs: [],
};

const initialWorld: WorldState = {
  hotelRealityStability: 100,
  anomalyAttention: 0,
  ruleNoticeVersion: 1,
  staffMode: "normal",
};

export const scenarioPack: ScenarioPack = {
  id: "after_evening_study",
  name: "晚自習結束之後",
  nameEn: "After Evening Study",
  tagline: "鐘響了三次，但時刻表上今晚只該響兩次。",
  description:
    "你是私立惠生中學住宿部的轉學生，被安排在學期中入住。校方規定夜間九點半後不得離開宿舍區，並發給你一份《夜間作息須知》。今晚是你住校的第一夜，走廊的日光燈白得像保健室，而你發現整層樓似乎只剩下你一個學生。",
  initialPlayer,
  initialWorld,
  locations: SCENARIO_LOCATIONS,
  events: SCENARIO_EVENTS,
  dialogues: SCENARIO_DIALOGUES,
  ruleSheets: SCENARIO_RULE_SHEETS,
  getRules,
  checkEnding: checkScenarioEnding,
};

export default scenarioPack;
